import { useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { deleteVehicleImage, getVehicleById, updateVehicle } from "../../api/vehicleApi";

const API_ORIGIN = "http://localhost:8070"; // ✅ backend host (change if deployed)

export default function EditVehicle() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState(null);
  const [saving, setSaving] = useState(false);

  const [newImages, setNewImages] = useState([]); // File[]

  // ✅ create previews once, revoke on cleanup
  const newPreviews = useMemo(() => newImages.map((f) => URL.createObjectURL(f)), [newImages]);

  useEffect(() => {
    return () => {
      newPreviews.forEach((u) => URL.revokeObjectURL(u));
    };
  }, [newPreviews]);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  useEffect(() => {
    getVehicleById(id)
      .then((res) => setVehicle(res.data))
      .catch((err) => {
        alert(err.response?.data?.message || "Vehicle not found");
        navigate("/vehicles");
      });
  }, [id, navigate]);

  if (!vehicle) return <p style={{ padding: 20 }}>Loading...</p>;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle((prev) => ({ ...prev, [name]: value }));
  };

  const existingCount = vehicle.images?.length || 0;

  // ✅ Correct: remaining slots must consider already selected newImages too
  const remainingSlots = Math.max(0, 4 - existingCount - newImages.length);

  const onPickImages = (e) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    // ✅ only allow as many as remainingSlots
    const allowed = files.slice(0, remainingSlots);
    setNewImages((prev) => [...prev, ...allowed]);
    e.target.value = "";
  };

  const removePickedNew = (index) => {
    setNewImages((prev) => prev.filter((_, i) => i !== index));
  };

  const removeExisting = async (filename) => {
    if (!window.confirm("Delete this photo?")) return;
    try {
      const res = await deleteVehicleImage(vehicle._id, filename);
      // backend returns { vehicle } (recommended) OR updated vehicle directly
      setVehicle(res.data.vehicle || res.data);
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    const yearNum = Number(vehicle.year);
    const priceNum = Number(vehicle.price);

    if (!vehicle.brand?.trim()) return alert("Brand is required");
    if (!vehicle.type) return alert("Vehicle type is required");
    if (Number.isNaN(yearNum)) return alert("Year must be a number");
    if (yearNum > currentYear) return alert(`Year cannot be in the future (max ${currentYear})`);
    if (yearNum < 1900) return alert("Year must be >= 1900");
    if (Number.isNaN(priceNum) || priceNum < 0) return alert("Price must be >= 0");

    const fd = new FormData();
    fd.append("brand", vehicle.brand.trim());
    fd.append("type", vehicle.type);
    fd.append("year", String(yearNum));
    fd.append("price", String(priceNum));
    fd.append("status", vehicle.status || "available");
    fd.append("vehicleNumber", (vehicle.vehicleNumber || "").trim());
    fd.append("details", (vehicle.details || "").trim());

    newImages.forEach((file) => fd.append("images", file));

    try {
      setSaving(true);
      const res = await updateVehicle(id, fd);

      // ✅ update local state with server response (includes images)
      setVehicle(res.data);
      setNewImages([]);
      alert("Vehicle updated!");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    } finally {
      setSaving(false);
    }
  };

  // ✅ Make image URLs absolute so they load correctly
  const toImgSrc = (url) => {
    if (!url) return "";
    if (url.startsWith("http")) return url;
    return `${API_ORIGIN}${url}`;
  };

  return (
    <div style={{ backgroundColor: "var(--bg)", paddingBottom: "40px", minHeight: "100vh" }}>
      {/* Page Header */}
      <div style={{
        paddingBottom: "40px",
        borderBottom: "1px solid var(--border)",
        marginBottom: "40px"
      }}>
        <h1 style={{
          fontSize: "32px",
          fontWeight: 800,
          color: "var(--text)",
          margin: "0 0 8px 0",
          letterSpacing: "-0.5px"
        }}>
          Edit Vehicle
        </h1>
        <p style={{
          fontSize: "15px",
          color: "var(--text-muted)",
          margin: 0,
          fontWeight: 300
        }}>
          Update vehicle details and manage photos
        </p>
      </div>

      {/* Form Container */}
      <div style={{
        maxWidth: "900px",
        margin: "0 auto",
        padding: "0 20px"
      }}>
        <div style={{
          backgroundColor: "var(--bg-card)",
          borderRadius: "12px",
          border: "1px solid var(--border)",
          padding: "32px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.05)"
        }}>
          <form onSubmit={submit} style={{ display: "flex", flexDirection: "column", gap: "24px" }}>

            {/* Basic Info Section */}
            <div>
              <div style={{
                fontSize: "14px",
                fontWeight: 700,
                color: "var(--text)",
                marginBottom: "16px",
                textTransform: "uppercase",
                letterSpacing: "0.4px"
              }}>
                Basic Information
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Brand <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <input
                    name="brand"
                    placeholder="Vehicle Brand"
                    value={vehicle.brand || ""}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>

                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Type <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <select
                    name="type"
                    value={vehicle.type || ""}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      cursor: "pointer",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    <option value="">Select Vehicle Type</option>
                    {vehicleTypes.map((t) => (
                      <option key={t} value={t}>
                        {t}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Year <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <input
                    name="year"
                    type="number"
                    placeholder="Year"
                    value={vehicle.year ?? ""}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>

                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Price (LKR) <span style={{ color: "var(--primary)" }}>*</span>
                  </label>
                  <input
                    name="price"
                    type="number"
                    placeholder="Price"
                    value={vehicle.price ?? ""}
                    onChange={handleChange}
                    required
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>
              </div>
            </div>

            {/* Status & Registration */}
            <div>
              <div style={{
                fontSize: "14px",
                fontWeight: 700,
                color: "var(--text)",
                marginBottom: "16px",
                textTransform: "uppercase",
                letterSpacing: "0.4px"
              }}>
                Status & Registration
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Status
                  </label>
                  <select
                    name="status"
                    value={vehicle.status || "available"}
                    onChange={handleChange}
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      cursor: "pointer",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    {statuses.map((s) => (
                      <option key={s} value={s}>
                        {s.charAt(0).toUpperCase() + s.slice(1)}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label style={{
                    display: "block",
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)",
                    marginBottom: "8px",
                    letterSpacing: "-0.2px"
                  }}>
                    Vehicle Number/Registration
                  </label>
                  <input
                    name="vehicleNumber"
                    placeholder="e.g., CAB-1234"
                    value={vehicle.vehicleNumber || ""}
                    onChange={handleChange}
                    style={{
                      width: "100%",
                      padding: "10px 14px",
                      fontSize: "14px",
                      border: "1px solid var(--border)",
                      borderRadius: "8px",
                      backgroundColor: "var(--bg)",
                      color: "var(--text)",
                      boxSizing: "border-box",
                      transition: "all 0.2s",
                      outline: "none"
                    }}
                    onFocus={(e) => {
                      e.currentTarget.style.borderColor = "var(--primary)";
                      e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                    }}
                    onBlur={(e) => {
                      e.currentTarget.style.borderColor = "var(--border)";
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  />
                </div>
              </div>
            </div>

            {/* Details Section */}
            <div>
              <label style={{
                display: "block",
                fontSize: "14px",
                fontWeight: 600,
                color: "var(--text)",
                marginBottom: "8px",
                letterSpacing: "-0.2px"
              }}>
                Additional Details
              </label>
              <textarea
                name="details"
                rows={4}
                placeholder="Describe additional features, condition, maintenance history, etc."
                value={vehicle.details || ""}
                onChange={handleChange}
                style={{
                  width: "100%",
                  padding: "10px 14px",
                  fontSize: "14px",
                  border: "1px solid var(--border)",
                  borderRadius: "8px",
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  boxSizing: "border-box",
                  fontFamily: "inherit",
                  transition: "all 0.2s",
                  outline: "none",
                  resize: "vertical"
                }}
                onFocus={(e) => {
                  e.currentTarget.style.borderColor = "var(--primary)";
                  e.currentTarget.style.boxShadow = "0 0 0 3px var(--primary-soft)";
                }}
                onBlur={(e) => {
                  e.currentTarget.style.borderColor = "var(--border)";
                  e.currentTarget.style.boxShadow = "none";
                }}
              />
            </div>

            {/* Existing Photos */}
            <div>
              <label style={{
                display: "block",
                fontSize: "14px",
                fontWeight: 600,
                color: "var(--text)",
                marginBottom: "12px",
                letterSpacing: "-0.2px"
              }}>
                Current Photos ({existingCount}/4)
              </label>

              {existingCount === 0 ? (
                <div style={{
                  padding: "16px",
                  backgroundColor: "var(--bg)",
                  borderRadius: "8px",
                  border: "1px dashed var(--border)",
                  fontSize: "13px",
                  color: "var(--text-muted)",
                  textAlign: "center"
                }}>
                  No photos uploaded yet
                </div>
              ) : (
                <div style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))",
                  gap: 12,
                  marginBottom: 16
                }}>
                  {vehicle.images.map((img) => (
                    <div key={img.filename} style={{
                      position: "relative",
                      borderRadius: "8px",
                      overflow: "hidden",
                      border: "1px solid var(--border)",
                      backgroundColor: "var(--bg)"
                    }}>
                      <div style={{
                        width: "100%",
                        aspectRatio: "4 / 3",
                        overflow: "hidden"
                      }}>
                        <img
                          src={toImgSrc(img.url)}
                          alt="vehicle"
                          style={{
                            width: "100%",
                            height: "100%",
                            objectFit: "cover"
                          }}
                        />
                      </div>

                      <button
                        type="button"
                        onClick={() => removeExisting(img.filename)}
                        style={{
                          position: "absolute",
                          top: "8px",
                          right: "8px",
                          width: "28px",
                          height: "28px",
                          borderRadius: "50%",
                          backgroundColor: "#ee4c47",
                          color: "white",
                          border: "none",
                          fontSize: "14px",
                          fontWeight: 700,
                          cursor: "pointer",
                          transition: "all 0.2s",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center"
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.transform = "scale(1.1)";
                          e.currentTarget.style.boxShadow = "0 4px 12px rgba(238, 76, 71, 0.3)";
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.transform = "scale(1)";
                          e.currentTarget.style.boxShadow = "none";
                        }}
                      >
                        ✕
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Add More Photos */}
            <div>
              <label style={{
                display: "block",
                fontSize: "14px",
                fontWeight: 600,
                color: "var(--text)",
                marginBottom: "12px",
                letterSpacing: "-0.2px"
              }}>
                Add More Photos (can add {remainingSlots} more)
              </label>

              <div style={{
                border: "2px dashed var(--border)",
                borderRadius: "8px",
                padding: "24px",
                textAlign: "center",
                backgroundColor: "var(--bg)",
                cursor: remainingSlots > 0 ? "pointer" : "not-allowed",
                opacity: remainingSlots > 0 ? 1 : 0.6,
                transition: "all 0.2s"
              }}
              onMouseEnter={(e) => remainingSlots > 0 && (e.currentTarget.style.borderColor = "var(--primary)")}
              onMouseLeave={(e) => (e.currentTarget.style.borderColor = "var(--border)")}>
                <input
                  type="file"
                  accept="image/*"
                  multiple
                  onChange={onPickImages}
                  disabled={remainingSlots <= 0}
                  style={{ display: "none" }}
                  id="moreImagesInput"
                />
                <label htmlFor="moreImagesInput" style={{
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  cursor: remainingSlots > 0 ? "pointer" : "not-allowed",
                  gap: "8px"
                }}>
                  <div style={{ fontSize: "28px" }}>📸</div>
                  <div style={{
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "var(--text)"
                  }}>
                    Click to upload photos
                  </div>
                  <div style={{
                    fontSize: "12px",
                    color: "var(--text-muted)"
                  }}>
                    {remainingSlots > 0 ? `PNG, JPG, GIF up to ${remainingSlots} image${remainingSlots !== 1 ? 's' : ''}` : "Maximum photos reached"}
                  </div>
                </label>
              </div>

              {/* New Image Previews */}
              {newPreviews.length > 0 && (
                <div style={{ marginTop: "20px" }}>
                  <div style={{
                    fontSize: "12px",
                    fontWeight: 600,
                    color: "var(--text-muted)",
                    marginBottom: "12px",
                    textTransform: "uppercase",
                    letterSpacing: "0.3px"
                  }}>
                    {newPreviews.length} new image{newPreviews.length !== 1 ? 's' : ''} to upload
                  </div>
                  <div style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))",
                    gap: 12
                  }}>
                    {newPreviews.map((src, idx) => (
                      <div key={src} style={{
                        position: "relative",
                        borderRadius: "8px",
                        overflow: "hidden",
                        border: "2px solid var(--primary)",
                        backgroundColor: "var(--bg)"
                      }}>
                        <div style={{
                          width: "100%",
                          aspectRatio: "4 / 3",
                          overflow: "hidden"
                        }}>
                          <img src={src} alt="preview" style={{
                            width: "100%",
                            height: "100%",
                            objectFit: "cover"
                          }} />
                        </div>

                        <button
                          type="button"
                          onClick={() => removePickedNew(idx)}
                          style={{
                            position: "absolute",
                            top: "8px",
                            right: "8px",
                            width: "28px",
                            height: "28px",
                            borderRadius: "50%",
                            backgroundColor: "#ee4c47",
                            color: "white",
                            border: "none",
                            fontSize: "14px",
                            fontWeight: 700,
                            cursor: "pointer",
                            transition: "all 0.2s",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center"
                          }}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.transform = "scale(1.1)";
                            e.currentTarget.style.boxShadow = "0 4px 12px rgba(238, 76, 71, 0.3)";
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.transform = "scale(1)";
                            e.currentTarget.style.boxShadow = "none";
                          }}
                        >
                          ✕
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Action Buttons */}
            <div style={{
              display: "flex",
              gap: "12px",
              paddingTop: "24px",
              borderTop: "1px solid var(--border)"
            }}>
              <button
                type="submit"
                disabled={saving}
                style={{
                  flex: 1,
                  padding: "12px 24px",
                  fontSize: "14px",
                  fontWeight: 700,
                  backgroundColor: "var(--primary)",
                  color: "white",
                  border: "none",
                  borderRadius: "8px",
                  cursor: saving ? "not-allowed" : "pointer",
                  transition: "all 0.2s",
                  letterSpacing: "0.3px",
                  opacity: saving ? 0.6 : 1
                }}
                onMouseEnter={(e) => !saving && (e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)")}
                onMouseLeave={(e) => !saving && (e.currentTarget.style.boxShadow = "none")}
              >
                {saving ? "Saving..." : "Save Changes"}
              </button>

              <button
                type="button"
                onClick={() => navigate("/vehicles")}
                style={{
                  padding: "12px 24px",
                  fontSize: "14px",
                  fontWeight: 600,
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  border: "1px solid var(--border)",
                  borderRadius: "8px",
                  cursor: "pointer",
                  transition: "all 0.2s",
                  letterSpacing: "0.2px"
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.backgroundColor = "var(--bg-hover)";
                  e.currentTarget.style.borderColor = "var(--primary)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor = "var(--bg)";
                  e.currentTarget.style.borderColor = "var(--border)";
                }}
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
